// /etc/bind/named.conf.options
options {
    // Basic DNS configuration
    directory "/var/cache/bind";
    recursion no;  // CRITICAL: Disable recursion on authoritative servers
    allow-query { any; };

    // Response Rate Limiting Configuration
    rate-limit {
        // Limit identical responses to 5 per second per client IP
        responses-per-second 5;

        // Apply stricter limits to error responses (NXDOMAIN, SERVFAIL)
        errors-per-second 2;

        // Limit responses for ANY queries specifically (common amplification vector)
        all-per-second 10;

        // Size of response tracking table (adjust based on traffic)
        window 15;  // Track responses over 15-second window

        // Slip factor: Send truncated responses (TC=1) occasionally to legitimate clients
        // This allows legitimate clients to retry over TCP while blocking amplification
        slip 2;  // Send 1 in 2 rate-limited responses as truncated

        // Log rate-limited responses for monitoring
        log-only no;  // Set to 'yes' for testing without enforcement

        // Exempt trusted clients from rate limiting (optional)
        exempt-clients {
            10.0.0.0/8;      // Internal networks
            172.16.0.0/12;   // Internal networks
            192.168.0.0/16;  // Internal networks
        };

        // IPv4-specific prefix length for tracking (group /24 subnets)
        ipv4-prefix-length 24;

        // IPv6-specific prefix length for tracking (group /56 subnets)
        ipv6-prefix-length 56;

        // Maximum size of rate-limit tracking table entries
        max-table-size 20000;

        // Referrals-per-second limit
        referrals-per-second 5;

        // NODATA responses per second
        nodata-per-second 5;

        // Queries per second from a single IP that trigger RRL
        nxdomains-per-second 5;
    };

    // Additional hardening measures
    version "DNS Server";  // Hide BIND version
    hostname none;          // Don't respond to hostname.bind queries
    server-id none;         // Don't respond to id.server queries

    // Disable ANY queries entirely (recommended)
    // ANY queries are rarely legitimate and commonly used for amplification
    minimal-any yes;  // BIND 9.11+ only returns minimal ANY responses

    // Enable DNSSEC validation
    dnssec-validation auto;
};

// Zone configuration example
zone "example.com" {
    type master;
    file "/etc/bind/zones/db.example.com";

    // Restrict zone transfers to authorized secondaries only
    allow-transfer { 10.0.1.2; 10.0.1.3; };

    // Disable recursion for zone queries
    allow-recursion { none; };
};

// Logging configuration for RRL monitoring
logging {
    channel rate_limit_log {
        file "/var/log/bind/rate-limit.log" versions 3 size 10m;
        severity info;
        print-time yes;
        print-category yes;
    };

    category rate-limit { rate_limit_log; };
};

# Terraform configuration for Route 53 DNS Firewall protection

# Create CloudWatch Log Group for DNS query logging
resource "aws_cloudwatch_log_group" "dns_query_logs" {
  name              = "/aws/route53/dns-firewall-queries"
  retention_in_days = 30
  kms_key_id        = aws_kms_key.dns_logs_key.arn

  tags = {
    Purpose = "DNS Amplification Attack Monitoring"
    Compliance = "ISO27001-A.13.1.1"
  }
}

# Enable Route 53 Resolver Query Logging
resource "aws_route53_resolver_query_log_config" "dns_logging" {
  name            = "dns-amplification-monitoring"
  destination_arn = aws_cloudwatch_log_group.dns_query_logs.arn

  tags = {
    Purpose = "DDoS Attack Detection"
  }
}

# Associate query logging with VPC
resource "aws_route53_resolver_query_log_config_association" "vpc_logging" {
  resolver_query_log_config_id = aws_route53_resolver_query_log_config.dns_logging.id
  resource_id                  = aws_vpc.main.id
}

# Create DNS Firewall Rule Group for Amplification Protection
resource "aws_route53_resolver_firewall_rule_group" "amplification_protection" {
  name = "dns-amplification-protection"

  tags = {
    Purpose = "Block DNS Amplification Attacks"
  }
}

# Block ANY queries (common amplification vector)
resource "aws_route53_resolver_firewall_rule" "block_any_queries" {
  name                    = "block-dns-any-queries"
  action                  = "BLOCK"
  block_response          = "NXDOMAIN"
  firewall_domain_list_id = aws_route53_resolver_firewall_domain_list.any_query_domains.id
  firewall_rule_group_id  = aws_route53_resolver_firewall_rule_group.amplification_protection.id
  priority                = 100

  # Block override settings
  block_override_dns_type = "CNAME"
  block_override_domain   = "blocked.example.com"
  block_override_ttl      = 60
}

# Domain list for blocking (use with managed threat intelligence feeds)
resource "aws_route53_resolver_firewall_domain_list" "any_query_domains" {
  name = "amplification-attack-domains"

  # In production, integrate with threat intelligence feeds
  # For now, block common amplification targets
  domains = [
    "*.in-addr.arpa",  # Reverse DNS lookups
    "*.ip6.arpa",      # IPv6 reverse lookups
  ]

  tags = {
    Purpose = "DNS Amplification Mitigation"
  }
}

# Rate limiting configuration (VPC DNS throttling)
resource "aws_route53_resolver_firewall_config" "vpc_rate_limiting" {
  resource_id = aws_vpc.main.id

  # Firewall fail-open behavior (set to DISABLED for strict security)
  firewall_fail_open = "DISABLED"
}

# Associate Firewall Rule Group with VPC
resource "aws_route53_resolver_firewall_rule_group_association" "vpc_protection" {
  name                   = "vpc-dns-amplification-protection"
  firewall_rule_group_id = aws_route53_resolver_firewall_rule_group.amplification_protection.id
  priority               = 101
  vpc_id                 = aws_vpc.main.id

  mutation_protection = "ENABLED"  # Prevent accidental rule removal

  tags = {
    Environment = "Production"
    Compliance  = "NIST-CSF-PR.IP-1"
  }
}

# CloudWatch Alarm for DNS amplification attack detection
resource "aws_cloudwatch_metric_alarm" "dns_query_spike" {
  alarm_name          = "dns-amplification-attack-detected"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "QueryCount"
  namespace           = "AWS/Route53Resolver"
  period              = 60
  statistic           = "Sum"
  threshold           = 10000  # Adjust based on baseline
  alarm_description   = "Alert when DNS query volume indicates amplification attack"
  treat_missing_data  = "notBreaching"

  dimensions = {
    ResolverQueryLogConfigId = aws_route53_resolver_query_log_config.dns_logging.id
  }

  alarm_actions = [aws_sns_topic.security_alerts.arn]
}

# CloudWatch Log Insights query for amplification attack detection
resource "aws_cloudwatch_query_definition" "amplification_detection" {
  name = "DNS Amplification Attack Detection"

  log_group_names = [
    aws_cloudwatch_log_group.dns_query_logs.name
  ]

  query_string = <<-QUERY
    fields @timestamp, query_name, query_type, srcaddr, srcport, rcode
    | filter query_type = "ANY" or query_type = "TXT" or query_type = "DNSSEC"
    | stats count() as request_count by srcaddr, query_type
    | filter request_count > 100
    | sort request_count desc
    | limit 50
  QUERY
}

# S3 bucket for long-term DNS log archival
resource "aws_s3_bucket" "dns_log_archive" {
  bucket = "dns-amplification-logs-archive"

  tags = {
    Purpose    = "DNS Attack Forensics"
    Retention  = "90-days"
  }
}

# Kinesis Data Firehose for streaming DNS logs to S3
resource "aws_kinesis_firehose_delivery_stream" "dns_log_stream" {
  name        = "dns-query-log-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.dns_log_archive.arn

    compression_format = "GZIP"
    prefix             = "dns-logs/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/"
    error_output_prefix = "errors/"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = "dns-delivery"
    }
  }
}

# VPC Security Group for DNS resolver endpoints
resource "aws_security_group" "dns_resolver" {
  name        = "route53-resolver-endpoints"
  description = "Security group for Route 53 Resolver endpoints with anti-amplification rules"
  vpc_id      = aws_vpc.main.id

  # Restrict DNS UDP to internal VPC only (prevent open resolver)
  ingress {
    description = "DNS UDP from VPC only"
    from_port   = 53
    to_port     = 53
    protocol    = "udp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  # Allow DNS TCP for zone transfers and large responses
  ingress {
    description = "DNS TCP from VPC only"
    from_port   = 53
    to_port     = 53
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "Allow all outbound"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name    = "route53-resolver-security"
    Purpose = "Prevent DNS Amplification"
  }
}
